import { ApiProperty } from '@nestjs/swagger';
import { IsString, IsEnum, MaxLength, IsNotEmpty } from 'class-validator';

export enum CategorieEnum {
  TECH = 'tech',
  SANTE = 'sante',
  EDUCATION = 'education'
}

export class CreateArticleDto {
  @ApiProperty({ description: 'Titre de l\'article', maxLength: 100 })
  @IsString()
  @IsNotEmpty()
  @MaxLength(100)
  titre: string;

  @ApiProperty({ description: 'Contenu complet de l\'article' })
  @IsString()
  @IsNotEmpty()
  contenu: string;

  @ApiProperty({ enum: CategorieEnum, description: 'Catégorie de l\'article' })
  @IsEnum(CategorieEnum)
  categorie: CategorieEnum;
}
